					flags:             flags
					serialized_length: serialized_length
				}
				keyword_loc:      keyword_loc
				conditions:       conditions
				then_keyword_loc: then_keyword_loc
				statements:       statements
			}
		}
		149 {
			serialized_length := u32(0)
			flags := ast.NodeFlags(reader.read_varuint()!)

			keyword_loc := reader.read_location()!
			do_keyword_loc_raw := reader.read_optional_location()!
			mut do_keyword_loc := ?ast.Location(none)
			if do_keyword_loc_raw.has_value {
				do_keyword_loc = do_keyword_loc_raw.value
			}
			closing_loc_raw := reader.read_optional_location()!
			mut closing_loc := ?ast.Location(none)
			if closing_loc_raw.has_value {
				closing_loc = closing_loc_raw.value
			}
			predicate := decode_node(mut reader, source, pool)!
			mut statements := ?ast.Node(none)
			if reader.read_optional_node_prefix()! {
				statements = decode_node(mut reader, source, pool)!
			}

			return ast.WhileNode{
				base:           ast.NodeBase{
					kind:              .while
					id:                node_id
					location:          location
					flags:             flags
					serialized_length: serialized_length
				}
				keyword_loc:    keyword_loc
				do_keyword_loc: do_keyword_loc
				closing_loc:    closing_loc
				predicate:      predicate
				statements:     statements
			}
		}
		150 {
			serialized_length := u32(0)
			flags := ast.NodeFlags(reader.read_varuint()!)

			opening_loc := reader.read_location()!
			content_loc := reader.read_location()!
			closing_loc := reader.read_location()!
			unescaped := reader.read_prism_string(source)!

			return ast.XStringNode{
				base:        ast.NodeBase{
					kind:              .x_string
					id:                node_id
					location:          location
					flags:             flags
					serialized_length: serialized_length
				}
				opening_loc: opening_loc
				content_loc: content_loc
				closing_loc: closing_loc
				unescaped:   unescaped
			}
		}
		151 {
			serialized_length := u32(0)
			flags := ast.NodeFlags(reader.read_varuint()!)

			keyword_loc := reader.read_location()!
			lparen_loc_raw := reader.read_optional_location()!
			mut lparen_loc := ?ast.Location(none)
			if lparen_loc_raw.has_value {
				lparen_loc = lparen_loc_raw.value
			}
			mut arguments := ?ast.Node(none)
			if reader.read_optional_node_prefix()! {
				arguments = decode_node(mut reader, source, pool)!
			}
			rparen_loc_raw := reader.read_optional_location()!
			mut rparen_loc := ?ast.Location(none)
			if rparen_loc_raw.has_value {
				rparen_loc = rparen_loc_raw.value
			}

			return ast.YieldNode{
				base:        ast.NodeBase{
					kind:              .yield
					id:                node_id
					location:          location
					flags:             flags
					serialized_length: serialized_length
				}
				keyword_loc: keyword_loc
				lparen_loc:  lparen_loc
				arguments:   arguments
				rparen_loc:  rparen_loc
			}
		}
		else {
			return error('unknown Prism node type: ${node_type}')
		}
	}
}
